import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

class CSVFormatTest {

    @Test
    void testGetCommentMarker_DefaultIsNull() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertNull(format.getCommentMarker());
    }

    @Test
    void testGetCommentMarker_SetCharacter() {
        CSVFormat format = CSVFormat.DEFAULT.withCommentMarker('#');
        assertEquals(Character.valueOf('#'), format.getCommentMarker());
    }

    @Test
    void testGetCommentMarker_SetCharacterObject() {
        CSVFormat format = CSVFormat.DEFAULT.withCommentMarker(Character.valueOf(';'));
        assertEquals(Character.valueOf(';'), format.getCommentMarker());
    }

    @Test
    void testGetCommentMarker_NullAfterSet() {
        CSVFormat format = CSVFormat.DEFAULT.withCommentMarker('!');
        format = format.withCommentMarker((Character) null);
        assertNull(format.getCommentMarker());
    }
}
